import test from 'node:test';
import assert from 'node:assert/strict';

import { retryRequest } from '../src/retry.ts';

test('caller abort signal reaches adapter and is never retried', async () => {
  const controller = new AbortController();
  controller.abort();
  let calls = 0;
  const adapter = async (signal: AbortSignal) => {
    calls += 1;
    if (signal !== controller.signal) throw new Error('signal identity lost');
    if (signal.aborted) {
      const error = new Error('aborted');
      error.name = 'AbortError';
      throw error;
    }
    return 'unexpected';
  };
  await assert.rejects(
    () => retryRequest(adapter, controller.signal),
    (error: Error) => error.name === 'AbortError',
  );
  assert.equal(calls, 1);
});
